import React, { useState } from 'react';
import './FloatingNewsletter.css';

const BASE_URL = 'http://localhost:4000';

export default function FloatingNewsletter() {
  const [email, setEmail] = useState('');
  const [submitted, setSubmitted] = useState(false);
  const [visible, setVisible] = useState(true);

  const handleSubscribe = async () => {
    if (!email.includes('@')) return;
    try {
      await fetch(`${BASE_URL}/subscribe`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email }),
      });
      setSubmitted(true);
      setEmail('');
    } catch (err) {
      console.error('Subscribe error:', err);
    }
  };

  if (!visible) return null;

  return (
    <div className="floating-newsletter">
      <button className="close-btn" onClick={() => setVisible(false)}>×</button>
      {!submitted ? (
        <>
          <p className="floating-title">Join our newsletter 💌</p>
          <div className="input-row">
            <input
              type="email"
              placeholder="Email..."
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
            <button className="icon-button" onClick={handleSubscribe}>
              ✓
            </button>
          </div>
        </>
      ) : (
        <p className="thank-you">Thanks for joining 💚</p>
      )}
    </div>
  );
}
